import { Router } from 'express';
import HamsterMemory from '../models/HamsterMemory.js';
import FeedPost from '../models/FeedPost.js';

const router = Router();

router.post('/visit', async (req, res) => {
  try {
    const { userId, hamsterId } = req.body;
    if (!userId || hamsterId == null) {
      return res.status(400).json({ error: 'Missing userId or hamsterId' });
    }
    await HamsterMemory.findOneAndUpdate(
      { userId, hamsterId },
      {
        $inc: { visitCount: 1 },
        $setOnInsert: { feedCount: 0 },
        $set: { lastVisit: new Date() },
      },
      { upsert: true, new: true }
    );
    return res.json({ ok: true });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to record visit' });
  }
});

router.post('/feed', async (req, res) => {
  try {
    const { userId, hamsterId, foodId, isFavourite } = req.body;
    if (!userId || hamsterId == null || !foodId) {
      return res.status(400).json({ error: 'Missing required fields' });
    }
    await HamsterMemory.findOneAndUpdate(
      { userId, hamsterId },
      {
        $inc: { feedCount: 1 },
        $setOnInsert: { visitCount: 0 },
        $set: { lastVisit: new Date() },
      },
      { upsert: true, new: true }
    );
    await FeedPost.create({ userId, hamsterId, foodId, isFavourite });
    return res.json({ ok: true });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to record feed' });
  }
});

router.get('/memory', async (req, res) => {
  try {
    const { userId, hamsterId } = req.query;
    if (!userId || !hamsterId) {
      return res.status(400).json({ error: 'Missing userId or hamsterId' });
    }
    const memory = await HamsterMemory.findOne({
      userId,
      hamsterId: Number(hamsterId),
    });
    if (!memory) {
      return res.json({ visitCount: 0, totalFeeds: 0, lastVisit: null });
    }
    return res.json({
      visitCount: memory.visitCount,
      totalFeeds: memory.feedCount,
      lastVisit: memory.lastVisit,
    });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to fetch memory' });
  }
});

export default router;

import 'dotenv/config';
import mongoose from 'mongoose';
import Hamster from '../models/Hamster.js';
import User from '../models/User.js';
import Conversation from '../models/Conversation.js';
import HamsterMemory from '../models/HamsterMemory.js';
import FeedPost from '../models/FeedPost.js';
import hamsters from '../../src/data/hamsters.js';

const MONGO_SRV = process.env.MONGO_SRV;
const MONGODB_DB_NAME = process.env.MONGODB_DB_NAME || 'hamster_matt_skills';

async function seed() {
  if (!MONGO_SRV) {
    console.error('MONGO_SRV not set in .env');
    process.exit(1);
  }

  console.log(`Connecting to MongoDB: ${MONGODB_DB_NAME}...`);
  await mongoose.connect(MONGO_SRV, { dbName: MONGODB_DB_NAME });
  console.log('Connected.');

  console.log('Clearing existing data...');
  await Promise.all([
    Hamster.deleteMany({}),
    User.deleteMany({}),
    Conversation.deleteMany({}),
    HamsterMemory.deleteMany({}),
    FeedPost.deleteMany({}),
  ]);
  console.log('Cleared.');

  console.log('Seeding hamsters...');
  const docs = hamsters.map((h, i) => ({
    id: i + 1,
    name: h.name,
    age: h.age,
    personality: h.personality,
    favouriteFood: h.favouriteFood,
    hobby: h.hobby,
    bio: h.bio,
    image: h.image,
    catchphrase: h.catchphrase,
    moodBoost: h.moodBoost,
    diary: h.diary,
  }));
  await Hamster.insertMany(docs);
  console.log(`Inserted ${docs.length} hamsters with ${docs.reduce((sum, h) => sum + h.diary.length, 0)} diary posts.`);

  await mongoose.disconnect();
  console.log('Seed complete.');
}

seed().catch((err) => {
  console.error('Seed failed:', err);
  process.exit(1);
});

